const enabled = (($env.MATTERMOST_RAG_INGEST_ENABLED || 'false').toLowerCase() === 'true');
if (!enabled) {
  return [{ json: { allowed: false, reason: 'Mattermost RAG ingest is disabled.' } }];
}

const body = $json.body || $json;
const rawConfig = $env.MATTERMOST_RAG_CHANNELS_JSON || '{}';
let config;
try {
  config = JSON.parse(rawConfig);
} catch (error) {
  return [{ json: { allowed: false, reason: 'Mattermost RAG channel config is invalid.' } }];
}

const channels = config.channels || config;
const channelId = body.channel_id || body.channelId || body.channel?.id || '';
const mapping = channels[channelId];
if (!mapping || !mapping.collection) {
  return [{ json: { allowed: false, reason: 'Channel is not allowed for RAG ingest.', channel_id: channelId } }];
}

const text = (body.text || body.message || body.post?.message || '').trim();
const files = body.files || body.file_infos || body.post?.metadata?.files || [];
return [{
  json: {
    allowed: true,
    collection: mapping.collection,
    channel_id: channelId,
    channel_name: mapping.channel_name || body.channel_name || '',
    user_name: body.user_name || body.username || body.user?.username || 'mattermost',
    post_id: body.post_id || body.post?.id || '',
    text,
    files
  }
}];
